+                rows.push((
+                    base.saturating_add(local_idx),
+                    DirEntry {
+                        ino: InodeNumber(dir_item.child_objectid),
+                        offset: 0,
+                        kind: Self::btrfs_dir_type_to_file_type(dir_item.file_type),
